+        #region External File To FileLink (PS-69087 #93)
+
+        /// <summary>
+        /// Direct coverage for <see cref="ExternalFileSystem"/>.<c>FetchFileFromExternalFileServiceAsync</c> —
+        /// the BL-private helper that pulls an external (S3) blob into <c>WebFileUploadDirectory</c> before
+        /// the FileLink upload pipeline takes over.
+        /// </summary>
+        [TestMethod]
+        public async Task FetchFileFromExternalFileServiceAsyncStoresFileInWebFileUploadDirectoryS3()
+        {
+            var presignError = new ErrorEncountered();
+            var s3Service = GetS3FileService();
+
+            var externalFileLocation = s3Service.GetPreSignedURLs(1, presignError)[0];
+            presignError.HasError.Should().BeFalse(presignError.Message);
+
+            var testFileName = TestDataBuilder.GetFilePath(TestDataBuilder.TestFiles.UPLOAD_SMALLPDF_A1REV1);
+            var uploadResult = await s3Service.UploadFileAsync(testFileName, externalFileLocation, null, default);
+            uploadResult.ResponseCode.Should().Be(HttpStatusCode.OK);
+
+            string serverFileName = null;
+
+            try
+            {
+                var requestedBy = GenerateRequestedByProject();
+                using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID);
+
+                var system = NewExternalFileSystemPinnedTo(s3Service);
+
+                var request = new FileRetrievalRequest
+                {
+                    ExternalFileLocation = externalFileLocation
+                };
+                var error = new ErrorEncountered();
+
+                serverFileName = await InvokeFetchFileFromExternalFileServiceAsync(system, request, error, portfolioDB, isOffline: false);
+
+                error.HasError.Should().BeFalse(error.Message);
+                serverFileName.Should().NotBeNullOrEmpty("BL fetch should return a server-side path on success");
+
+                var webFileUploadDirectory = portfolioDB.WebFileUploadDirectory;
+
+                using (new AssertionScope())
+                {
+                    serverFileName.Should().StartWith(webFileUploadDirectory, "fetched file lands in WebFileUploadDirectory");
+                    File.Exists(serverFileName).Should().BeTrue("downloaded file persisted to disk");
+                    new FileInfo(serverFileName).Length.Should().BeGreaterThan(0, "downloaded file is non-empty");
+                }
+            }
+            finally
+            {
+                if (!string.IsNullOrEmpty(serverFileName))
+                {
+                    Global.KillAFile(serverFileName, true);
+                }
+                await DeleteFileFromS3Async(externalFileLocation);
+            }
+        }
+
+        #endregion // External File To FileLink (PS-69087 #93)
+
+        #region External File To FMS (PS-69087 #94)
+
+        /// <summary>
+        /// End-to-end coverage for <see cref="ExternalFileSystem"/>.<c>DownloadExternalFileAndStoreInFMSAsync</c> —
+        /// external (S3) blob → <c>WebFileUploadDirectory</c> → <c>FMSDirectory</c> via
+        /// <see cref="ExternalFileSystem.InitiateExternalFileRetrievalForFMSAsync"/> with foreground execution.
+        /// </summary>
+        [TestMethod]
+        public async Task DownloadExternalFileAndStoreInFMSAsyncStoresExternalFileInFMSDirectoryS3()
+        {
+            var presignError = new ErrorEncountered();
+            var s3Service = GetS3FileService();
+
+            var externalFileLocation = s3Service.GetPreSignedURLs(1, presignError)[0];
+            presignError.HasError.Should().BeFalse(presignError.Message);
+
+            var testFileName = TestDataBuilder.GetFilePath(TestDataBuilder.TestFiles.UPLOAD_SMALLPDF_A1REV1);
+            var uploadResult = await s3Service.UploadFileAsync(testFileName, externalFileLocation, null, default);
+            uploadResult.ResponseCode.Should().Be(HttpStatusCode.OK);
+
+            var folder = CreateNewFolderAndSavePS();
+            folder.FolderID.Should().NotBe(0);
+
+            var clientFileName = $"{Generate.String("ExternalToFMS")}{Path.GetExtension(testFileName)}";
+
+            try
+            {
+                var fileRequest = new ExternalFileUploadRequest
+                {
+                    FolderId = folder.FolderID.Value.ToString(),
+                    FileName = clientFileName,
+                    ExternalLocation = externalFileLocation,
+                    Unmonitored = false
+                };
+
+                var error = new ErrorEncountered();
+                var result = await new ExternalFileSystem().InitiateExternalFileRetrievalForFMSAsync(
+                    fileRequest, GenerateRequestedByProject(), error, default, forceForegroundExecution: true);
+
+                error.HasError.Should().BeFalse(error.Message);
+                result.Should().NotBeNull("DMS file request returned");
+                result.Status.Should().Be(DMSFileRequest.Statuses.Success, "external download finalised into FMS");
+                result.ClientFileName.Should().NotBeNullOrEmpty("FileSID populated on success");
+
+                RecordNewFilePS(result.ClientFileName);
+
+                var dmsFile = GetFilePS(result.ClientFileName);
+
+                using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), m_oProject.ProjectID);
+                var fmsDirectory = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+                var fmsFilePath = Path.Combine(fmsDirectory, Global.CreateFileGUIDFromGUID(dmsFile.GUID));
+
+                using (new AssertionScope())
+                {
+                    File.Exists(fmsFilePath).Should().BeTrue("external file moved into FMSDirectory");
+                    new FileInfo(fmsFilePath).Length.Should().Be(Global.CTIFileLen(testFileName), "FMS copy matches uploaded file size");
+                }
+            }
+            finally
+            {
+                await DeleteFileFromS3Async(externalFileLocation);
+            }
+        }
+
+        #endregion // External File To FMS (PS-69087 #94)
+
+        #region Helpers
+
+        private static ExternalFileSystem NewExternalFileSystemPinnedTo(IExternalFileService service)
+        {
+            var factory = Substitute.For<IExternalFileServiceFactory>();
+            factory.GetExternalFileService(Arg.Any<ExternalFileServiceTypes>()).Returns(service);
+            return new ExternalFileSystem(factory);
+        }
+
+        private static async Task<string> InvokeFetchFileFromExternalFileServiceAsync(
+            ExternalFileSystem system,
+            FileRetrievalRequest request,
+            ErrorEncountered error,
+            IDBHelper portfolioDB,
+            bool isOffline)
+        {
+            var method = typeof(ExternalFileSystem).GetMethod(
+                "FetchFileFromExternalFileServiceAsync",
+                BindingFlags.NonPublic | BindingFlags.Instance);
+
+            method.Should().NotBeNull("ExternalFileSystem.FetchFileFromExternalFileServiceAsync exists");
+
+            // ReSharper disable once PossibleNullReferenceException
+            var task = (Task<string>)method.Invoke(system, new object[] { request, error, portfolioDB, isOffline, default(CancellationToken) });
+            return await task;
+        }
+
+        #endregion // Helpers
     }
 }

