+
+            var externalFileLocation = azureService.GetPreSignedURLs(1, presignError)[0];
+            presignError.HasError.Should().BeFalse(presignError.Message);
+
+            var testFileName = TestDataBuilder.GetFilePath(TestDataBuilder.TestFiles.UPLOAD_SMALLPDF_A1REV1);
+            var uploadResult = await azureService.UploadFileAsync(testFileName, externalFileLocation, null, default);
+            uploadResult.ResponseCode.Should().Be(HttpStatusCode.Created);
+
+            var folder = CreateNewFolderAndSavePS();
+            folder.FolderID.Should().NotBe(0);
+
+            var clientFileName = $"{Generate.String("ExternalToFMS")}{Path.GetExtension(testFileName)}";
+
+            try
+            {
+                var fileRequest = new ExternalFileUploadRequest
+                {
+                    FolderId = folder.FolderID.Value.ToString(),
+                    FileName = clientFileName,
+                    ExternalLocation = externalFileLocation,
+                    Unmonitored = false
+                };
+
+                var error = new ErrorEncountered();
+                var result = await new ExternalFileSystem().InitiateExternalFileRetrievalForFMSAsync(
